import type {
  HoverCardCompactProps,
  HoverCardCompactEmits,
  HoverCardCompactSlots,
  HoverCardUi
} from '@soybeanjs/headless/hover-card';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the HoverCard component.
 */
export interface HoverCardProps extends HoverCardCompactProps {
  /**
   * class of popup
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<HoverCardUi>;
}

/**
 * Events for the HoverCard component.
 */
export type HoverCardEmits = HoverCardCompactEmits;

/**
 * Slots for the HoverCard component.
 */
export type HoverCardSlots = HoverCardCompactSlots;

export { default as SHoverCard } from './hover-card.vue';

export type * from '@soybeanjs/headless/hover-card';
export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const hoverCardVariants = scv({
  slots: {
    positioner: 'w-max',
    popup: [
      'z-50 w-64 rounded-md border bg-popover text-popover-foreground shadow-md outline-none will-change-transform',
      'data-[state=open]:animate-in data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95',
      'data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95',
      'data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2'
    ],
    arrow: 'w-1em h-0.5em fill-popover stroke-border'
  },
  variants: {
    size: {
      xs: {
        popup: 'w-48 p-3 text-2xs',
        arrow: 'text-3xs'
      },
      sm: {
        popup: 'w-56 p-3.5 text-xs',
        arrow: 'text-2xs'
      },
      md: {
        popup: 'w-64 p-4 text-sm',
        arrow: 'text-xs'
      },
      lg: {
        popup: 'w-72 p-4.5 text-base',
        arrow: 'text-sm'
      },
      xl: {
        popup: 'w-80 p-5 text-lg',
        arrow: 'text-base'
      },
      '2xl': {
        popup: 'w-96 p-5.5 text-xl',
        arrow: 'text-lg'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
